INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('aboriginal-57f41407-moex-00512', 'aboriginal-57f41407', 'aboriginal-57f41407-moex-110-1611a566', 'sub-aboriginal-57f41407-03', NULL, 'single_choice', '除有急迫情形或曾行準備程序之事件外，法院一併送達起訴狀與言詞辯論期日通知書於被告時，其距言詞 辯論期日，至少應有多少日為就審期間？', '["10日", "15日", "20日", "30日"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:17+00:00", "source_pdf_sha1": "9acea49fa720", "answer_pdf_sha1": "85b04c6abf8a", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "605", "s": "0812", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "錄事"}'::jsonb, NULL),
  ('aboriginal-57f41407-moex-00513', 'aboriginal-57f41407', 'aboriginal-57f41407-moex-110-1611a566', 'sub-aboriginal-57f41407-03', NULL, 'single_choice', '甲起訴請求乙給付積欠之貨款新臺幣（下同）20萬元，訴訟中甲、乙私下達成和解，約定於乙給付15萬 元後，甲即撤回起訴。乙依約給付15萬元後，甲並未撤回起訴。於乙向法院抗辯後，法院應如何處理？', '["以該訴欠缺當事人適格，駁回原告之訴", "以該訴欠缺訴之利益，駁回原告之訴", "以該訴已發生撤回之效力，毋庸繼續審判", "以該訴訟欠缺訴訟上之成立要件，駁回原告之訴"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:17+00:00", "source_pdf_sha1": "9acea49fa720", "answer_pdf_sha1": "85b04c6abf8a", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "605", "s": "0812", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "錄事"}'::jsonb, NULL),
  ('aboriginal-57f41407-moex-00514', 'aboriginal-57f41407', 'aboriginal-57f41407-moex-110-1611a566', 'sub-aboriginal-57f41407-03', NULL, 'single_choice', '甲起訴請求乙給付貨款新臺幣（下同）100萬元。乙在言詞辯論時稱其不爭執貨款債權之存在，惟已於某 日清償。甲雖承認收到此100萬元，但主張該款項係乙請其代收另筆款項，欲將來轉付丙者。乙則否認曾 有另筆代收款項存在之事實。下列敘述何者正確？', '["乙表示對貨款債權之事實不爭執，是為自認", "乙表示對貨款債權之事實不爭執，是為認諾", "甲應就清償事實負舉證責任", "若法院就有無另筆代收款項之事實為認定時，其為判決理由之判斷，將生既判力"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:17+00:00", "source_pdf_sha1": "9acea49fa720", "answer_pdf_sha1": "85b04c6abf8a", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "605", "s": "0812", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "錄事"}'::jsonb, NULL),
  ('aboriginal-57f41407-moex-00515', 'aboriginal-57f41407', 'aboriginal-57f41407-moex-110-1611a566', 'sub-aboriginal-57f41407-03', NULL, 'single_choice', '關於調解程序之進行，下列敘述何者正確？', '["調解事件涉及關係人為7歲以下之無程序能力人時，司法事務官應依職權與主任調解委員，共同至該關 係人之學校或安置機構進行調解，否則該調解程序違法", "調解委員於必要時，得依職權命當事人或其法定代理人到場進行調解", "法定代理人無正當理由未隨同當事人參與調解者，法院應以裁定處新臺幣（下同）6000元以下之罰鍰", "當事人無正當理由不於調解期日到場者，法院得以裁定處3000元以下之罰鍰"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:17+00:00", "source_pdf_sha1": "9acea49fa720", "answer_pdf_sha1": "85b04c6abf8a", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "605", "s": "0812", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "錄事"}'::jsonb, NULL),
  ('aboriginal-57f41407-moex-00516', 'aboriginal-57f41407', 'aboriginal-57f41407-moex-110-1611a566', 'sub-aboriginal-57f41407-03', NULL, 'single_choice', '適用簡易訴訟程序之第一審程序，法院應以幾次期日辯論終結為原則？', '["5次", "3次", "2次", "1次"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:17+00:00", "source_pdf_sha1": "9acea49fa720", "answer_pdf_sha1": "85b04c6abf8a", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "605", "s": "0812", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "錄事"}'::jsonb, NULL),
  ('aboriginal-57f41407-moex-00517', 'aboriginal-57f41407', 'aboriginal-57f41407-moex-110-1611a566', 'sub-aboriginal-57f41407-03', NULL, 'single_choice', '適用小額訴訟程序之第一審事件，下列何者，非民事訴訟法規定言詞辯論期日通知書應表明之事項？', '["兩造得於期日前先自行協商，如被告按期履行債務得免除其一部之給付", "該事件適用小額訴訟程序審理", "應於期日攜帶所用證物並偕同所舉證人到場", "審判長所指定之言詞辯論期日時間"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:17+00:00", "source_pdf_sha1": "9acea49fa720", "answer_pdf_sha1": "85b04c6abf8a", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "605", "s": "0812", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "錄事"}'::jsonb, NULL),
  ('aboriginal-57f41407-moex-00518', 'aboriginal-57f41407', 'aboriginal-57f41407-moex-110-1611a566', 'sub-aboriginal-57f41407-03', NULL, 'single_choice', '關於救濟程序，下列敘述何者錯誤？', '["對於第二審法院之判決提起上訴，非以該判決適用法規顯有錯誤為理由，不得為之", "對於確定判決，得以其適用法規顯有錯誤為理由，提起再審之訴", "對於抗告法院所為抗告無理由之裁定提起再抗告，僅得以其適用法規顯有錯誤為理由", "對於上訴利益逾新臺幣150萬元之簡易訴訟程序第二審判決提起第三審上訴，僅得以其適用法規顯有錯 誤為理由"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:17+00:00", "source_pdf_sha1": "9acea49fa720", "answer_pdf_sha1": "85b04c6abf8a", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "605", "s": "0812", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "錄事"}'::jsonb, NULL),
  ('aboriginal-57f41407-moex-00519', 'aboriginal-57f41407', 'aboriginal-57f41407-moex-110-1611a566', 'sub-aboriginal-57f41407-03', NULL, 'single_choice', '被告為訴訟標的之認諾時，法院應如何處理？', '["法院應為被告敗訴之判決", "法院應為不受理之判決", "法院仍應斟酌被告先前所為之陳述與主張，再為判決", "法院可不經言詞辯論為判決"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:17+00:00", "source_pdf_sha1": "9acea49fa720", "answer_pdf_sha1": "85b04c6abf8a", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "605", "s": "0812", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "錄事"}'::jsonb, NULL),
  ('aboriginal-57f41407-moex-00520', 'aboriginal-57f41407', 'aboriginal-57f41407-moex-110-1611a566', 'sub-aboriginal-57f41407-03', NULL, 'single_choice', '關於第三人撤銷訴訟程序，下列敘述何者正確？', '["確定終局判決對於有法律上利害關係之第三人造成不利益時，該第三人均得提起撤銷之訴", "曾參加訴訟，而參加時未提出足以影響判決結果之攻擊或防禦方法者，得提起撤銷之訴", "為促進法律上利害關係第三人之程序選擇權，可循其他法定程序救濟者，亦得提起撤銷之訴", "有法律上利害關係之第三人提起撤銷之訴時，必須以確定終局判決之兩造為共同被告"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:17+00:00", "source_pdf_sha1": "9acea49fa720", "answer_pdf_sha1": "85b04c6abf8a", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "605", "s": "0812", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "錄事"}'::jsonb, NULL),
  ('aboriginal-57f41407-moex-00521', 'aboriginal-57f41407', 'aboriginal-57f41407-moex-110-1611a566', 'sub-aboriginal-57f41407-03', NULL, 'single_choice', '關於再審之訴，下列敘述何者正確？', '["參加訴訟，得與提起再審之訴合併為之", "未曾參加訴訟而對於確定判決有法律上利害關係之人，得對於該判決提起再審之訴", "再審之訴，法院認無再審理由而判決駁回後，當事人不得再以同一事由，對於該駁回再審之訴之確定判 決，提起再審之訴", "法院就再審之訴為判決前，均應行言詞辯論程序"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:17+00:00", "source_pdf_sha1": "9acea49fa720", "answer_pdf_sha1": "85b04c6abf8a", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "605", "s": "0812", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "錄事"}'::jsonb, NULL)
